{
  "title": "Primary 3 Science Exam",
   "description": "Assessing primary 3 students' knowledge in basic science concepts",
   "timeLimit": 60,
   "passingScore": 70,
   "sections": [
       {
           "name": "A",
           "description": "Multiple Choice questions",
           "questions": [
               {
                   "text": "What is the process called when plants make their own food from sunlight?",
                   "type": "multiple-choice",
                   "points": 5,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Respiration", "isCorrect": false, "letter": "A"},
                       {"text": "Photosynthesis", "isCorrect": true, "letter": "B"},
                       {"text": "Decomposition", "isCorrect": false, "letter": "C"},
                       {"text": "Fermentation", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               },
               {
                   "text": "Which part of the human body helps us to breathe?",
                   "type": "multiple-choice",
                   "points": 5,
                   "difficulty": "easy",
                   "options": [
                       {"text": "Heart", "isCorrect": false, "letter": "A"},
                       {"text": "Lungs", "isCorrect": true, "letter": "B"},
                       {"text": "Brain", "isCorrect": false, "letter": "C"},
                       {"text": "Liver", "isCorrect": false, "letter": "D"}
                   ],
                   "correctAnswer": "B"
               }
           ]
       },
       {
           "name": "B",
           "description": "Open Ended questions",
           "questions": [
               {
                   "text": "Describe the water cycle and its importance to our planet.",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "The water cycle is the process by which water moves from the Earth to the atmosphere and back again. It is important because it helps to distribute water around the planet, which is necessary for life."
               },
               {
                   "text": "What are the main parts of a plant and what are their functions?",
                   "type": "open-ended",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "The main parts of a plant are the roots, stem, leaves, and flowers. The roots absorb water and nutrients from the soil, the stem supports the plant and transports water and nutrients, the leaves make food through photosynthesis, and the flowers produce seeds."
               }
           ]
       },
       {
           "name": "C",
           "description": "True / False questions",
           "questions": [
               {
                   "text": "The sun is a star that is closest to the Earth.",
                   "type": "true-false",
                   "points": 5,
                   "difficulty": "easy",
                   "options": [
                       {"text": "True", "isCorrect": true, "letter": "A"},
                       {"text": "False", "isCorrect": false, "letter": "B"}
                   ],
                   "correctAnswer": "True"
               }
           ]
       },
       {
           "name": "D",
           "description": "Short Answer questions",
           "questions": [
               {
                   "text": "What is the largest planet in our solar system?",
                   "type": "short-answer",
                   "points": 5,
                   "difficulty": "easy",
                   "correctAnswer": "Jupiter"
               }
           ]
       },
       {
           "name": "E",
           "description": "Fill in Blank questions",
           "questions": [
               {
                   "text": "The process of plants making their own food from sunlight is called ___",
                   "type": "fill-in-blank",
                   "points": 5,
                   "difficulty": "easy",
                   "correctAnswer": "photosynthesis"
               }
           ]
       },
       {
           "name": "F",
           "description": "Matching questions",
           "questions": [
               {
                   "text": "Match the following animals with their habitats: lion - ___ , fish - ___ , bird - ___",
                   "type": "matching",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "savannah, ocean, sky"
               }
           ]
       },
       {
           "name": "G",
           "description": "Ordering questions",
           "questions": [
               {
                   "text": "Put the following steps of the water cycle in order: evaporation, condensation, precipitation",
                   "type": "ordering",
                   "points": 10,
                   "difficulty": "medium",
                   "correctAnswer": "evaporation, condensation, precipitation"
               }
           ]
       }
   ]
}
